good.code:
from mini_calendar.parser import (
    is_leap_year, days_in_month, parse_iso_date,
)
def test_is_leap_year_1900_is_false():
    assert is_leap_year(1900) is False

def test_is_leap_year_2000_is_true():
    assert is_leap_year(2000) is True

def test_days_in_february_leap_is_29():
    assert days_in_month(2024, 2) == 29

def test_days_in_month_zero_raises_value_error():
    import pytest
    with pytest.raises(ValueError):
        days_in_month(2024, 0)

def test_days_in_month_thirteen_raises_value_error():
    import pytest
    with pytest.raises(ValueError):
        days_in_month(2024, 13)

def test_parse_iso_date_returns_tuple():
    result = parse_iso_date('2024-02-29')
    assert result == (2024, 2, 29)
    assert isinstance(result, tuple)

