from csv_normalizer.normalizer import (
    coerce_value, is_numeric, normalize_header, parse_row,
)
def test_normalize_header_collapses_runs():
    assert normalize_header('A  B__C') == 'a_b_c'

def test_normalize_header_strips_trailing_underscore():
    assert normalize_header('hello!') == 'hello'

def test_normalize_header_empty_returns_col():
    assert normalize_header('!!!') == 'col'

def test_coerce_value_false_literal():
    assert coerce_value('false') is False

def test_coerce_value_no_alias_is_false():
    assert coerce_value('no') is False

def test_is_numeric_negative_int():
    assert is_numeric('-7') is True

def test_parse_row_quoted_with_comma():
    assert parse_row('"a,b",c') == ['a,b', 'c']

